/* 边框必须包含三个要素：宽度(粗细)、样式(线条类型)、颜色 */
.box {
  /* 分开写 */
  border-width: 2px;
  border-style: solid; /* solid实线, dashed虚线, dotted点线 */
  border-color: #ff0000;

  /* 综合简写（最常用，无顺序要求） */
  border: 2px solid red;

  /* 也可以单独给某一条边设置 */
  border-bottom: 5px dashed blue;
  border-left: none; /* 去掉左边框 */
}

.box {
  /* 外边距语法与Padding完全一样（顺时针法则） */
  margin: 10px 20px 30px 40px;
}

/* 💡 经典技巧：盒子水平居中 */
.container {
  width: 800px; /* 必须有固定的宽度 */
  margin: 0 auto; 
  /* 上下间距为0，左右间距自动(auto)平分剩余空间 */
}

/* 默认的标准盒模型（会撑大盒子） */
.box1 {
  box-sizing: content-box;
}

/* 切换为怪异盒模型（不会撑大盒子，向内挤压） */
.box2 {
  box-sizing: border-box;
}

/* 💡 现代开发最佳实践：强制所有元素使用怪异盒模型 */
/* 把它写在你每一个项目的最开头！ */
* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

body.text:
现象二：父子元素垂直塌陷
父盒子里面有个子盒子，给子盒子设置 margin-top: 50px;
子盒子没有往下走，反而是父盒子带着子盒子一起往下掉了50px！

