/* 方案1：给父盒子写死高度（不灵活，很少用） */

/* 方案2：使用 overflow: hidden 触发 BFC（常用）*/
.parent {
  overflow: hidden; 
}

/* 方案3：终极黑魔法 - clearfix 类（业界标准） */
/* 把这段代码放到公共样式中 */
.clearfix::after {
  content: "";      /* 创建一个伪元素在末尾 */
  display: block;   /* 必须是块级元素 */
  clear: both;      /* 核心：清除左右两边的浮动影响 */
}

/* 使用时给塌陷的父盒子加上类名 */
/* <div class="parent clearfix"> ... </div> */

/* 常见场景：永远停靠在右下角的“回到顶部”按钮 */
.back-to-top {
  position: fixed;
  bottom: 50px;
  right: 50px;
  width: 40px;
  height: 40px;
  background: #00bcd4;
}

/* 常见场景：固定在顶部的全局导航栏 */
.header-nav {
  position: fixed;
  top: 0;
  left: 0;
  width: 100%; /* 绝对/固定定位后元素默认由内容撑开，需要重新设定宽度 */
  z-index: 999; /* 保证层级最高，不被页面其他内容遮挡 */
}

/* 把鼠标变成“点击手势”：暗示元素可以点击 */
.btn {
  cursor: pointer;  
}

/* 文本输入图标（工字型） */
.text-area {
  cursor: text;
}

/* 禁用标识（红圈斜杠）：暗示不可操作 */
.disabled-btn {
  cursor: not-allowed;
}

/* 十字星定位标 */
.target {
  cursor: crosshair;
}

.box {
  width: 200px;
  height: 200px;
  background: #333;

  /* 基础用法：四周全是 10px 的圆角 */
  border-radius: 10px;

  /* 变成一个完美的圆形（前提是正方形盒子） */
  border-radius: 50%; 
}

.pill {
  width: 300px;
  height: 50px;
  background: blue;

  /* 胶囊形状（两端半圆）：给一个远大于高度一半的值 */
  border-radius: 999px; 
}

/* 语法：X轴偏移 Y轴偏移 模糊半径 扩散半径 颜色 */

.card {
  /* 经典柔和阴影：没有X偏移，向下偏10px，模糊20px，轻微透明黑 */
  box-shadow: 0 10px 20px rgba(0, 0, 0, 0.1);
}

.card-hover {
  /* 内阴影（在前面加 inset） */
  box-shadow: inset 0 0 10px rgba(0,0,0,0.5);
}

.glowing-btn {
  /* 发光效果：无偏移，大模糊，使用亮色系 */
  box-shadow: 0 0 15px rgba(0, 255, 255, 0.8);
}

.btn {
  background: #3498db;
  color: white;
  width: 100px;
  height: 40px;

  /* 语法：属性 持续时间 动画节奏 延迟 */
  /* 告诉浏览器：当我的背景色和宽度发生改变时，请用0.3秒平滑过渡 */
  transition: background 0.3s ease, width 0.3s ease;

  /* 或者偷懒的写法，监控所有属性： */
  /* transition: all 0.3s ease; */
}

.btn:hover {
  /* 鼠标悬停时触发状态改变 */
  background: #2ecc71;
  width: 120px;
}

/* 我们要计算这些组合选择器的总分，从左到右比较每一位的数字大小 */

/* 题型1： */
#header .nav li { color: red; }
/* 1个ID(0,1,0,0) + 1个类(0,0,1,0) + 1个标签(0,0,0,1) = 0,1,1,1 */

/* 题型2： */
.container ul.list li.item { color: blue; }
/* 3个类(0,0,3,0) + 2个标签(0,0,0,2) = 0,0,3,2 */

/* 题型3： */
#header li.item { color: green; }
/* 1个ID(0,1,0,0) + 1个类(0,0,1,0) + 1个标签(0,0,0,1) = 0,1,1,1 */

/* 比较方法：先比第一位，一样大再比第二位...
题型1 和 题型3 得分相同(0,1,1,1)，题型3写在后面，根据就近原则，最终颜色为 green。
题型2 得分最高位是百位(3)，比不上题型1的千位(1)，所以哪怕它写得再长，也是失败的！ */

