/* 卡片基础布局 */
.food-card {
  float: left;
  width: 300px;
  margin: 15px;
  background: #fff;
  border-radius: 8px;
  overflow: hidden; /* 防止里面的图片超出圆角范围 */

  /* 初始阴影与动画过渡配置 */
  box-shadow: 0 4px 6px rgba(0,0,0,0.1);
  transition: all 0.3s ease;
}

/* 悬停时的视觉特效 */
.food-card:hover {
  /* Y轴上浮10像素 */
  transform: translateY(-10px);
  /* 阴影加重且变大，产生立体感 */
  box-shadow: 0 15px 25px rgba(0,0,0,0.2);
}
